// // This module is designed to implement a synchronous up-down counter with a 4-bit count value. The counter increments when 'up' is high and decrements when 'up' is low. The 'resetn' input is active low.
module up_down_counter (
	input clk,
	input resetn,
	input up,
	output reg [3:0] count);

	always @(posedge clk) begin
		if (~resetn) count <= 4'b0000;
		else if (up) count <= count + 1;
		else count <= count - 1;
	end
endmodule
